DELETE FROM tb_software_package t
WHERE t.id IN

    #{id}

mapper.select:
SELECT 
FROM tb_software_package t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.device_code = #{deviceCode}


    AND t.software_pn = #{softwarePn}


    AND t.package_name = #{packageName}


    AND t.package_code = #{packageCode}


    AND t.package_url = #{packageUrl}


    AND t.package_size = #{packageSize}


    AND t.package_md5 = #{packageMd5}


    AND t.package_desc = #{packageDesc}


    AND t.package_type = #{packageType}


    AND t.package_source = #{packageSource}


    AND t.base_software_pn = #{baseSoftwarePn}


    AND t.package_adaptive_level = #{packageAdaptiveLevel}


    AND t.adaptive_assembly_pn = #{adaptiveAssemblyPn}


    AND t.release_date = #{releaseDate}


    AND t.estimated_install_time = #{estimatedInstallTime}


    AND t.ota = #{ota}


    AND t.description = #{description}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.id DESC
